INSERT INTO quiz_question (id, word_bank_id, contextual_cloze, chinese_translation, correct_answer, distractor1, distractor2, distractor3, explanation_root_affix, explanation_mnemonic, created_at, updated_at) VALUES
('7e4c0723-0b9d-5702-b982-0202349ee356', 'b4caa950-57f1-4d44-9082-14aaf844a513', 'Even though he is a brave soldier, he is still ___ of spiders.', '雖然他是一名勇敢的士兵，但他仍然害怕蜘蛛。', 'afraid', 'proud', 'angry', 'hungry', 'a- 前綴表示「處於某種狀態」。', 'a (處於) + afraid (害怕) → 處於害怕的狀態。', '2026-07-06 18:42:28', '2026-07-06 18:42:28'),
('f0d20fe8-d59b-5f4b-bbed-ce42b76ddeb2', '91428d6f-22bd-45c5-972c-8c608e93124e', 'The two parties finally ___ to the terms of the settlement.', '雙方終於同意了和解條款。', 'agreed', 'decided', 'refused', 'talked', 'a- (趨向/向) + gree (使人滿意/一致) → 趨向一致的意見。', 'agree (同意) → a (向) + gree (一致) → 想法向同一處。', '2026-07-06 19:14:20', '2026-07-06 19:14:20'),
('ca27eb3d-6474-5ab7-9353-acd53235f72a', '727e62de-3a07-4167-af4a-77eabfa18856', 'To the ___ of everyone in the room, the magician suddenly disappeared into thin air.', '令房間裡的每個人都感到驚奇的是，魔術師突然消失在空氣中。', 'amazement', 'boredom', 'confusion', 'comfort', 'amaze (使驚訝) + -ment (名詞字尾) → 驚奇', '想像走進一個巨大的 maze (迷宮)，看到奇幻景象時會感到 amazement (驚奇)。', '2026-07-06 20:35:17', '2026-07-06 20:35:17'),
('6cc7f2d5-7def-5de0-bd11-7b8265c0df32', '2148b226-a44f-453e-ac23-6e310525b3c4', 'The rain stopped ___ the sun began to shine.', '雨停了，隨即陽光開始灑落。', 'and', 'but', 'yet', 'or', '連接詞，用於連接兩個連續發生的事件。', '事件 A → 事件 B', '2026-07-05 09:37:28', '2026-07-05 09:37:28'),
('1cc467d7-319b-5aa6-8705-a06db5f9aa52', 'e88a6792-5990-4905-a606-6529b45af048', 'Despite his great success, his ___ behavior makes many of his colleagues feel disrespected.', '儘管他取得了巨大的成功，但他那種傲慢的行為讓許多同事感到不被尊重。', 'arrogant', 'humble', 'generous', 'patient', '來自拉丁語 ar- (向) + rog (要求) → 意指「要求他人服從」，引申為傲慢的。', '想像一個人總是要求別人聽他的，這種自以為是的態度就是 arrogant。', '2026-07-07 00:17:02', '2026-07-07 00:17:02'),
('2cf0cf16-261b-5ca0-b2aa-2ebce83cce8a', 'a3111bfd-ea64-4091-821d-6c37f0f00a34', 'We will meet ___ the end of the street.', '我們會在街道的盡頭見面。', 'at', 'in', 'on', 'to', '介系詞', 'at 用於表示位置的盡頭。', '2026-07-05 11:38:17', '2026-07-05 11:38:17'),
('50ac1ef4-d2bd-572d-ba9d-82fc2238e99e', '318901f8-2a17-4dff-bb6b-4164349879b3', 'The teacher praised the student for his excellent ___ toward learning new things.', '老師稱讚這名學生對於學習新事物有著極佳的態度。', 'attitude', 'ability', 'talent', 'memory', 'att (趨向/朝向) + itude (狀態/性質) → 趨向某事的心態或狀態。', '想像你把注意力 (attention) 轉向某件事的「狀態」，那就是你的「態度」。', '2026-07-07 02:21:23', '2026-07-07 02:21:23'),
('c1a80a91-8dc1-55bd-9ad2-516945db5f06', 'bbb2fcee-f431-417f-9611-641469dcd9d1', 'I wanted to go to the party, ___ I had to study for the exam.', '我想去參加派對，但我必須為考試讀書。', 'but', 'so', 'and', 'because', 'conj. (連接詞) 用於連接兩個對比或相反的子句。', '用於表示「但是」，前後語意通常會發生轉折 → but', '2026-07-05 14:07:23', '2026-07-05 14:07:23'),
('8198aeb7-5358-5fe1-a864-3b816aba3f12', '5d20b73d-7d29-498d-92b3-52636f5571d1', 'We ___ the fruit to keep it for a long time.', '我們將水果裝罐以保存很久。', 'can', 'buy', 'cook', 'sell', '表示『將...裝罐保存』的動作。', '把食物裝進 can (罐頭) 裡。', '2026-07-05 11:43:54', '2026-07-05 11:43:54'),
('df96ddd6-7402-5c0d-bf3f-d69fadddfc22', 'e45fd5c2-e6df-4093-81de-99e5f5537ce8', 'This is a good ___ to learn English.', '這是個學習英文的好機會。', 'chance', 'dream', 'song', 'food', 'chance 為名詞，表示「機會」。', 'chance → 機會，把握機會 (take a chance)！', '2026-07-07 03:07:49', '2026-07-07 03:07:49'),
('7d767dc1-5f05-5b23-bf0d-d3eff9b5a7aa', '8a4c0ad5-9e31-4486-970e-07a9ab4605dc', 'The teacher spoke ___ so that everyone could understand.', '老師說得很清楚，好讓每個人都能聽懂。', 'clearly', 'loudly', 'angrily', 'hungrily', 'clearly 是副詞，由形容詞 clear 加上 ly 組成。', '講話要 clear (清晰地)，大家才聽得懂。', '2026-07-07 04:32:29', '2026-07-07 04:32:29'),
('88e1d17b-a25d-5ce4-aa5e-ba63764eebaa', 'a9ed4f3e-1974-4639-986c-18fa7d9af990', 'Look! The school bus is ___ down the street.', '看！校車正沿著街道開過來。', 'coming', 'flying', 'sitting', 'dancing', 'come 表示「來、到來」。', '看到 come 就想到「到來」的意思。', '2026-07-07 05:15:46', '2026-07-07 05:15:46'),
('435cf38e-5ccd-5eaa-a933-4bb210c4f256', '3618111e-eb30-4e3b-b1bb-d7eb327585a6', 'I am a student. ___ name is Tom.', '我是一個學生。我的名字是 Tom。', 'my', 'your', 'his', 'her', 'my 為第一人稱單數的所有格，表示「我的」。', 'my (我的) → 記住 my 是用來指「我的」東西。', '2026-07-05 13:06:23', '2026-07-05 13:06:23');
